package pe.org.camaracomercioica.protestos.repository; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import pe.org.camaracomercioica.protestos.model.*; import java.time.Instant; import java.util.List; public interface SolicitudRepository extends JpaRepository<Solicitud,Long>{@Query("select s from Solicitud s where (:estado is null or s.estado=:estado) and (:entidadId is null or s.entidad.id=:entidadId)") Page<Solicitud> filtrar(@Param("estado") EstadoSolicitud estado,@Param("entidadId") Long entidadId,Pageable pageable);Page<Solicitud> findBySolicitanteEmailIgnoreCase(String email,Pageable pageable);long countByEstado(EstadoSolicitud estado);List<Solicitud> findByCreadoEnBetween(Instant desde,Instant hasta);}
